import React from 'react'
import styled from 'styled-components'
import avatar from './static/HedMayner.png'


const Header = styled.div `
display:flex;
justify-content:space-between;
align-items:center;
margin:20px 0;
`

const Avatar = styled.div `
border-radius:50%;
width:150px;
height:150px;
background-image:url(${avatar});
background-position:center;
background-size:cover;
`

const LeftPart = styled.div `
display:flex;
justify-content:center;
align-items:center;
`

const Username = styled.div `
margin:0 40px;
`

const SeparationLineStraight = styled.div `
background-color:grey;
height:60px;
width:1px;
`

const TransactionWrapper = styled.div `
margin:0 40px;
display:flex;
justify-content:center;
align-items:center;
flex-direction:column;
`

const Transaction = styled.div `
font-size:1.2rem;
font-weight:800;
`

const TransactionWord = styled.div `
font-size:0.8rem;
`

const FollowersWrappper = styled.div `
margin:0 40px;
display:flex;
justify-content:center;
align-items:center;
flex-direction:column;
`

const Followers = styled.div `
font-size:1.2rem;
font-weight:800;
`

const FollowersWord = styled.div `
font-size:0.8rem;
`

const EditProfile = styled.div `
text-align:center;
line-height:40px;
width:150px;
height:40px;
background-color:#1C1C1C;
border-radius:7px;
border:1;
color:white;
font-size:0.9rem;
`

const SeparationLineBig = styled.hr `
background-color:grey;
`

export default function MeHeader () {



	return (
		<>
		<Header>
			<LeftPart>
				<Avatar />
				<Username>NoahHong</Username>
				<SeparationLineStraight />
				<TransactionWrapper>
					<Transaction>3</Transaction>
					<TransactionWord>Transactions</TransactionWord>
				</TransactionWrapper>
				<SeparationLineStraight />
				<FollowersWrappper>
					<Followers>3</Followers>
					<FollowersWord>Transactions</FollowersWord>
				</FollowersWrappper>
			</LeftPart>
			<EditProfile>Edit Profile</EditProfile>
		</Header>
		<SeparationLineBig/>
		</>
	)
}
